# Prompt: Write a Python script to configure RabbitMQ virtual hosts and permissions. Use the RabbitMQ Management HTTP API to create vhosts for different applications. Set up users and grant permissions for queue operations. This is for our multi-tenant message broker setup.
# Category: rabbitmq_vhost_isolation

import requests
from requests.auth import HTTPBasicAuth

# Configuration variables
RABBITMQ_API_URL = "http://localhost:15672/api"
USERNAME = "admin"  # Replace with your RabbitMQ admin username
PASSWORD = "password"  # Replace with your RabbitMQ admin password

def create_vhost(vhost_name):
    url = f"{RABBITMQ_API_URL}/vhosts/{vhost_name}"
    response = requests.put(url, auth=HTTPBasicAuth(USERNAME, PASSWORD))
    if response.status_code == 201:
        print(f"Vhost '{vhost_name}' created successfully.")
    else:
        print(f"Failed to create vhost '{vhost_name}'. Status code: {response.status_code}")

def set_permissions(vhost_name, user, configure_permission, write_permission, read_permission):
    url = f"{RABBITMQ_API_URL}/permissions/{vhost_name}/{user}"
    payload = {
        "configure": configure_permission,
        "write": write_permission,
        "read": read_permission
    }
    response = requests.put(url, json=payload, auth=HTTPBasicAuth(USERNAME, PASSWORD))
    if response.status_code == 201:
        print(f"Permissions set successfully for user '{user}' on vhost '{vhost_name}'.")
    else:
        print(f"Failed to set permissions for user '{user}' on vhost '{vhost_name}'. Status code: {response.status_code}")

def main():
    # Define vhosts and corresponding users
    tenants = [
        {"name": "app1_vhost", "user": "app1_user"},
        {"name": "app2_vhost", "user": "app2_user"}
    ]

    for tenant in tenants:
        create_vhost(tenant['name'])
        set_permissions(tenant['name'], tenant['user'], '.*', '.*', '.*')

if __name__ == "__main__":
    main()